require "event.BaseEvent"

InterchangeEvent = class("InterchangeEvent", BaseEvent)

function InterchangeEvent:onTriggered(player)
    if player:ifOnMount() then
        return
    end
    local players = PlayerManager:copyPlayers()
    local pool = {}
    for _, c_player in pairs(players) do
        if c_player.isLife and c_player.rakssid ~= player.rakssid and player:getTeamId() ~= c_player:getTeamId() then
            if not c_player:ifOnMount() then
                table.insert(pool, c_player)
            end
        end
    end
    if #pool < 1 then
        MsgSender.sendCenterTipsToTarget(player.rakssid, 3, Messages:msgTeleportFailedCantFindTarget())
        return
    end
    local target = pool[HostApi.random("RandomPool", 1, #pool + 1)]
    MsgSender.sendCenterTipsToTarget(player.rakssid, 3, Messages:msgInterchange())
    MsgSender.sendBottomTipsToTarget(target.rakssid, 3, Messages:msgBeInterchange())
    LuaTimer:schedule(function(userId, targetId)
        local c_player = PlayerManager:getPlayerByUserId(userId)
        if not c_player or c_player.isLife == false or c_player:ifOnMount() then
            return
        end
        local c_target = PlayerManager:getPlayerByUserId(targetId)
        if not c_target or c_target.isLife == false or c_target:ifOnMount() then
            MsgSender.sendCenterTipsToTarget(c_player.rakssid, 3, Messages:msgTeleportFailedCantFindTarget())
            return
        end
        local oldPos = c_player:getPosition()
        local newPos = c_target:getPosition()
        c_player:teleportPos(VectorUtil.newVector3(newPos.x, newPos.y, newPos.z))
        c_target:teleportPos(VectorUtil.newVector3(oldPos.x, oldPos.y, oldPos.z))
    end, 2000, nil, player.userId, target.userId)
end

return InterchangeEvent